// Extract and validate partner data
const body = $input.first().json.body;

const requiredFields = ['nom', 'email', 'raison_sociale', 'siret', 'siren'];
const errors = [];

for (const field of requiredFields) {
  if (!body[field]) {
    errors.push(`${field} is required`);
  }
}

// Validate SIRET format (14 digits)
if (body.siret && !/^\d{14}$/.test(body.siret.toString())) {
  errors.push('SIRET must be 14 digits');
}

// Validate SIREN format (9 digits)
if (body.siren && !/^\d{9}$/.test(body.siren.toString())) {
  errors.push('SIREN must be 9 digits');
}

if (errors.length > 0) {
  throw new Error(errors.join(', '));
}

// Set defaults
const partnerData = {
  nom: body.nom,
  email: body.email,
  raison_sociale: body.raison_sociale,
  siret: body.siret,
  siren: body.siren,
  telephone: body.telephone || null,
  type: body.type || 'apporteur_affaires',
  adresse: body.adresse || null,
  commission_taux_niveau1: body.commission_taux_niveau1 ?? 10,
  commission_taux_niveau2: body.commission_taux_niveau2 ?? 3,
  statut: 'actif',
  domaine_personnalise: (body.type === 'white_label' ? body.domaine_personnalise : null) || null,
  nom_affiche: (body.type === 'white_label' ? body.nom_affiche : null) || null,
  couleur_primaire: (body.type === 'white_label' ? body.couleur_primaire : null) || null
};

return { json: partnerData };
